import { date_utils } from '../dateinterval';
import { formatTickWrapByMode } from '../tickWrap';
import { getTextBound } from '../textBound';
import { mathCeil } from '../../core/zc-constants';
import { getTickWidth } from '../tick-labels';
import { defined } from '../../utils/zcutils';
import { DataProcessor as P } from '../../core/data-processor';
import { TIME_DATATYPE } from '../../core/datatype-constants';
import { addMinmaxToTicks } from './min-max-ticks';
import { getLongestTick } from '../tick-labels';
import { _customExtent } from '../../axis-parser/tick-parser-helpers/tick-domain-helpers/tick-linear-helpers';
import { pick } from '../../utils/zcutils';
import { getFormattedValue } from '../../formatter/formatter';

export function getTimeTicks() {
    let _ = this,
        { tickCount, interval } = _.config,
        ticks,
        tickIndices,
        specifierIndex = _.groupby ? _.order : null,
        { column } = _,
        { datatype } = column;
    // #ZC1187
    if (!defined(column[datatype])) {
        column[datatype] = _.format;
    }
    let formattingSubFunction = _.subFormatType(_.format, _.domain[1] - _.domain[0]);
    let start = new Date(_.domain[0]),
        end = new Date(_.domain[1]);

    // get the date utils 1326
    let dateInterval = new date_utils(_.format);
    dateInterval.useUTC = _.format.useUTC === true;

    let maxData = dateInterval.getMaxDate(), // save it
        longestFormattedTick = getFormattedValue(_.format, maxData, TIME_DATATYPE, _.chart, 'axis', null, null, specifierIndex);
    longestFormattedTick = formatTickWrapByMode(
        longestFormattedTick,
        _.rotationConfig.tickAlignmentMode,
        _.maxSize.horizontal,
        _.maxSize.vertical,
        _.styles.fontSize
    );
    let dimension = getTextBound(longestFormattedTick, _.styles.fontSize, _.styles.fontFamily);
    let space = getTickWidth(_.side, dimension, _.margin, _.rotation, _.styles.fontSize, _.orient);

    // tickCount = _.size / space;
    tickCount = pick(tickCount, _.size / space);
    // get the date range
    if (_.isAutoFormat) {
        ticks = _.tickH.scale(_customExtent(this)).ticks();
        longestFormattedTick = null;
    } else {
        var dateRange = dateInterval.range(start, end, mathCeil(tickCount), formattingSubFunction, interval);

        ticks = dateRange.TICKS;
    }
    ticks = addMinmaxToTicks.call(this, ticks);

    return { ticks, longestFormattedTick };
}

export function recalculteTicksAfterBestFit(tickCountH, bestFitTickModel) {
    let { maxTickCount } = bestFitTickModel,
        { ticks, ticks_formatted, customTickInfo, tickRotateMode, tickAutoRotation, rotation, tickCount } = tickCountH;
    if (this.isAutoFormat) {
        // let timeScale = existingScale || scale;
        let timeScale = this.scale;
        // #ZC2211 only if
        let reduceAutoTick = tickCount > maxTickCount && tickRotateMode && rotation === 0;

        ticks = timeScale.ticks(reduceAutoTick ? maxTickCount * 0.5 : maxTickCount);

        if (this.tickCount > maxTickCount && !reduceAutoTick) {
            // change the rotation manually as there are no control
            // over calculating ticks in auto format to avoid overlapping
            rotation = tickAutoRotation;
        }
        ticks_formatted = ticks.map(d => timeScale.tickFormat()(d));
        this.longestTick = getLongestTick(
            ticks_formatted,
            ticks,
            this.styles && this.styles.fontSize,
            this.styles && this.styles.fontFamily,
            customTickInfo && customTickInfo.styles
        ); //TODO check
    } else {
        let start = new Date(this.domain[0]),
            end = new Date(this.domain[1]);
        let dateInterval = new date_utils(this.format);
        dateInterval.useUTC = this.format.useUTC === true;
        let dateRange = dateInterval.range(start, end, maxTickCount, this.format.subfunction, this.config.interval);
        ticks = dateRange.TICKS;
        ticks = addMinmaxToTicks.call(this, ticks);
        // formatAccessor = formatAccessor(axisH, { formatter, format, styles, maxSize, groupby, rotation });
        ticks_formatted = ticks.map(this.formatAccessor);
    }
    return { ticks, ticks_formatted, rotation };
}

export function generateTimeGroupByAdapter(ticks) {
    let { dataObject } = this.chart;
    if (this.groupby && !defined(dataObject.hierarchical)) {
        dataObject.hierarchical = new P.HierarchicalTimeDataAdapter(
            this.chart,
            ticks,
            this.format.groupby,
            this.datatype !== TIME_DATATYPE,
            this.column
        );
    } else if (this.groupby) {
        dataObject.hierarchical.update(ticks);

        /*
        Find ranges for column branches
        */
        let rangeScaleUtils = dataObject.hierarchical.setScaleForRange(this.chart.axes.x.rangeScale);
        dataObject.hierarchical.pivotLayout.setRanges('column', rangeScaleUtils);
    }
}
